INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 3.414, 0.0, "カリン", 1, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 62, 1000001, 190801, 1, "2025/01/31 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 3.099, 0.0, "カリン", 1, "ミッションをクリアして、\n報酬をゲットしましょう！", 62, 1000002, 190801, 2, "2025/01/31 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 2.801, 0.0, "カリン", 1, "受け取ることができる\n報酬があるようです\n確認してみてください", 63, 1000003, 190801, 3, "2025/01/31 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 2, 0.0, 0.0, "カリン", 1, "報酬がもらえますよ！\nチェックしてみてください", 63, 1000004, 190801, 4, "2025/01/31 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1, 2.12, 0.0, "カリン", 1, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 64, 1000005, 190801, 5, "2025/01/31 12:00:00", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 1.68, 0.0, "カリン", 1, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 64, 1000006, 190801, 6, "2025/01/31 12:00:00", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1, 2.33, 0.0, "カリン", 1, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 64, 1000007, 190801, 7, "2025/01/31 12:00:00", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 7, 5.18, -6.0, "ラビリスタ", 10201, "今度の敵は、アタシにとっても\n放ってはおけない存在だ\n少年、アタシも全力で行くからさ\n一緒に守ろう、この世界を", 61, 1020101, 133701, 101, "2025/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 8.77, -2.0, "クリスティーナ", 10201, "退屈の吹き飛ぶような\n戦いの気配がするなぁ坊や\nさっさとワタシをそこへ連れてゆけ\n世界も守ってやるさ、ついでにな", 61, 1020102, 133901, 201, "2025/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 6, 1, 15.5, 0.0, "ネネカ", 10201, "おや、私の力が必要……と？\nグレゴールが手伝うそうですよ\n私は戦わないのか、という顔ですね\n……考えておきます", 61, 1020103, 133801, 301, "2025/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 5, 9.061, 0.0, "ランファ", 10202, "わたしだけの歌…\n一緒に、探してくれる…？\nあなたがいれば…\nもっとがんばれるから…", 61, 1020201, 134301, 101, "2025/02/28 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 7.699, 0.0, "チカ", 10202, "同じ唱喚士として、仲間として\n私にできることをします\n…これも、あなたが\n背中を押してくれたおかげですよ", 61, 1020202, 134401, 201, "2025/02/28 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 8.595, 0.0, "アオイ", 10203, "世界の平和が私とクローチェさんに\nかかってるんですよね？\nぼっちには過大すぎる期待ですけど\nふ、二人でなら背負ってみせます！", 61, 1020301, 134601, 101, "2025/03/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 7.758, 0.0, "クローチェ", 10203, "新しく手に入れたこの翼で…\nナイトさんがどこにいたって\nわたし、駆けつけちゃいますよっ！\nクローチェ・エアリアル発進ですっ", 61, 1020302, 134501, 201, "2025/03/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 6, 7.0, 0.0, "ルイズマリー", 10204, "今日はダーリンとの初デート♪\n二人でショッピングして、その後は\n…って私、指名手配されてる！？\nちょ、た…助けてダーリン～！！", 61, 1020401, 132302, 101, "2025/04/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 7.904, 0.0, "イロハ", 10204, "ルイちゃんのおばあちゃん優しくて\nいつもにこにこで、イロハ大好き♪\nでも一番好きなのは、角がすっごく\n大きくてかっこいいとこなんだ～♪", 61, 1020402, 132402, 201, "2025/04/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 2, 8.487, 0.0, "ソノ", 10204, "ノゾミちゃんのおかげで売上が安定\nしてきたのに、臨時休業、痛すぎる\n…ま、ルイちゃんのために\n一肌脱ぐか。行くよイロハ～", 61, 1020403, 132502, 301, "2025/04/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 8.763, 0.0, "カノン", 10205, "ヲ～ッホッホ♪\nあたくし様と同じお空気を吸える\nお幸運を噛みしめなさいですわ～♪\nヲ～ッホッホッホ～♪", 61, 1020502, 134901, 101, "2025/05/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 3, 6.417, 0.0, "ツムギ", 10205, "いきますよ騎士さん！\nカノンさんと力を合わせて…力を…\n…本当にあの人なんなんです？\nこれまでになく不安なんですけど！", 61, 1020503, 134801, 201, "2025/05/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 7, 10.335, 0.0, "エリス", 10206, "『願いが叶う海岸』か…怪しい\nだというのに、阿賀斗紫布菜たちは\n呑気に戯れている…見ていられない\n騎士クンは、わたしが守ってみせる", 61, 1020601, 135001, 101, "2025/06/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 4, 6.281, 0.0, "シェフィ", 10206, "せっかくの夏休みなんだし\nたまにはビーチでゆっくりしましょ\n…え、もしかしてこの夏もあんまり\n休めなかったりする感じなの？", 61, 1020602, 135101, 201, "2025/06/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 12.244, 0.0, "プレシア", 10206, "いっぱい。たべて\nおおきく。なると\nせーぎ。まもれる。はず\nお兄。いっしょに。スイカ。たべよ", 61, 1020603, 135201, 301, "2025/06/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 8, 6.339, 0.0, "クリア", 10207, "ひと夏の冒険のはじまりです！\nアネモネさんも楽しんでくれたら\n…できれば、もう少し\n仲良くなれたらうれしいな…", 61, 1020701, 135301, 101, "2025/07/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 7, 9, 8.184, 0.0, "アネモネ", 10207, "─幻の花…\n本当にあるのか謎─ですけど\n探すくらいは、\n付き合ってもいいです", 61, 1020702, 135401, 201, "2025/07/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 9, 2, 3.906, 0.0, "アイラ", 10208, "あははっ！　笑う門には福来る！\n笑ってればきっと、複製世界にも\n未来はやってくるって信じてる！\nそうだよね、シナツちゃん！", 61, 1020801, 129101, 101, "2025/08/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 14.465, 0.0, "シナツ", 10208, "繰り返されるリセットの先の未来\n何度願っても手に入らなかった未来\n…でも、私は諦めない。絶対にだ\nキミも同じだろ…アイラ？", 61, 1020802, 129201, 201, "2025/08/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 3, 8.662, 0.0, "ヒヨリ", 10208, "アイラの世界のみんなも、\n一生懸命生きてるんだ…！\n…なのに、世界の危機だなんて！\nあたし、絶対、絶対力になるよ！", 61, 1020803, 100101, 301, "2025/08/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 3, 10.915, 0.0, "レイ", 10208, "シナツ…もう一人の私\n彼女が大切にしている世界を\n絶対に終わらせはしない…！\n彼女と笑い合える未来のために！", 61, 1020804, 100301, 401, "2025/08/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 7, 6.042, 0.0, "ユキノ", 10209, "あ、ど、ども…\nあ、あんま見ねぇでくれっと\nその、恥ずかしくて…\n体が熱くなって、溶けちまう…", 61, 1020901, 135802, 101, "2025/09/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 1, 9.402, 0.0, "サツキ", 10209, "なんで俺が幽霊に…意味不明だ\nこれじゃ死んでも死にきれねェ\n悪ィがこれも何かの縁だ、\nよろしく頼むぜ騎士公", 61, 1020902, 135903, 201, "2025/09/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 8, 1, 8.16, 0.0, "ルルィ", 10209, "う、うじゅる…\nサツキ姉しゃまを助けるためにも\nまずは、腹ごしらえでしゅね…！\nタコ焼き、召し上がってくだしゃい", 61, 1020903, 136902, 301, "2025/09/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 2, 5.0, 0.0, "カスミ", 10210, "ひさしぶりのジオ・ゲヘナ\n歓迎パーティーで起きた殺人事件！\nランドソルの名探偵の名にかけて\n解き明かしてみせようじゃないか！", 61, 1021001, 137401, 101, "2025/10/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 1, 8.12, 0.0, "アラクネ", 10210, "…わたしはどこの誰なのでしょう\nどこから来てどこへ行くのでしょう\nこの事件の真相が分かれば、\n何かが掴めるような気がいたします", 61, 1021002, 136001, 201, "2025/10/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 2, 6.386, 0.0, "ナーナ", 10210, "ナーナ、すいりとかろんぱとか、\nむずかしくてわかんないけど…\nお友だちとドーナツのためならっ\nせーいっぱいがんばるよっ！", 61, 1021003, 136202, 301, "2025/10/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 3, 4, 7.438, 0.0, "ユイ", 10211, "騎士クンに想いを伝えたい…だから\nミソラちゃん、わたしがんばるね！\n…あれ？　わたし、なんでこんなに\n必死になってるんだろう…？", 61, 1021101, 136402, 101, "2025/11/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 5, 8.35, 0.0, "ミソラ", 10211, "騎士さんとのデートはわたしに\nお任せです★　なのでユイさんは\n安心して計画に専念して…たくさん\nドキドキしちゃってくださいね", 61, 1021102, 136302, 201, "2025/11/30 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 5.0, 0.0, "シズル", 10212, "新しい年がやってくるね！\nお正月の料理も飾りつけも、\nお姉ちゃんにお任せだよ♪\nみんなで楽しく新年を迎えよう！", 61, 1021201, 136501, 101, "2025/12/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 5.25, 0.0, "リノ", 10212, "おうちの掃除もトラブルも、 \n世界を揺るがす大ピンチも！\n今年のことは今年のうちに \nサッサと片付けちゃいますっ！", 61, 1021202, 137902, 201, "2025/12/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 7.5, 0.0, "ラビリスタ", 10212, "年の瀬はギルドマスターも\nつい駆け回っちゃう忙しい時期だ！\n一年いろいろあったけど\nお互いイイ年を迎えよう、少年！", 61, 1021203, 106801, 301, "2025/12/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 8.204, 0.0, "ライラエル", 10213, "漂う異国の料理の香り…それだけで\n世界中を旅した気分に浸れますね\nふふ、ほらクローチェ\nあまりはしゃぎすぎないように…♪", 61, 1021301, 126501, 101, "2026/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 7.176, 0.0, "ネフィ＝ネラ", 10213, "異界の姫君と煮炊きにて競い合う…\n感奮興起、いとをかし\n華やかなる祭典と相成るよう、一肌\n脱がせていただきとう存じまする", 61, 1021302, 129701, 201, "2026/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 5, 8.602, 0.0, "ヴァイオレット", 10213, "『ビストロプリンセス』のために\n料理の特訓を重ねてまいりました\nこの料理で騎士様の…い、いえ\n皆様の心とお腹を満たしますわ！", 61, 1021303, 133101, 301, "2026/01/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 3, 10.14, 0.0, "ライラエル", 10213, "多様な味わいが織りなすハーモニー\nそれこそが我が国の矜持です\nもしもそれを乱すようであれば\nわたしも優しくはありませんよ？", 61, 1021304, 138101, 102, "2026/02/06 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 7, 10.152, 0.0, "ネフィ＝ネラ", 10213, "煉獄の穢土にてひと際輝く民草の心\n此れを守護りまするがわっちの責務\n如何な困難待ち受けようと\n不退転の矜持に揺らぎはありんせん", 61, 1021305, 138201, 202, "2026/02/06 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 3, 9.688, 0.0, "ヴァイオレット", 10213, "裏世界の皆様は危機を脱し、\n残るはランドソルの皆様のみ…\n彼らを救い出すために、どうか…\nお立ち下さいペコリーヌ姫…！", 61, 1021306, 138001, 302, "2026/02/06 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1, 5.928, 0.0, "ペコリーヌ", 10213, "みなさん、お待たせしちゃいました\nペコリーヌ、完全復活です☆\nみなさんの食卓を守るため\nもう二度と、わたしはめげません！", 61, 1021307, 138301, 401, "2026/02/12 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 2, 9.19, 0.0, "ワカナ", 10214, "成行きで参加することになっちゃっ\nた尻相撲大会。ううっ、恥ずかしい\nけどやるしかないよね。…騎士さん\nいっぱい応援してくださいね？", 61, 1021401, 138702, 101, "2026/02/28 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 3, 8.724, 0.0, "シオリ", 10214, "「お姉ちゃんを守れる自分になる」\nあの日の約束、今こそ果たしてみせ\nます。例えお姉ちゃんに背くことに\nなっても。例えそれが尻相撲でも！", 61, 1021402, 138802, 201, "2026/02/28 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 4, 1, 7.758, 0.0, "グレイス", 10215, "私がへんたいふしんしゃさんって…\nただ生きているだけなのに、ひどい\n…まぁ死んでるんですけど…とか\n言ってる暇もない感じですか？", 61, 1021501, 138902, 101, "2026/03/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 6, 4, 6.375, 0.0, "キョウカ", 10215, "あの、助けてください！\n私がへんたいふしんしゃさんに\nなっちゃったみたいなんです…！\nどういう意味かは私もわかりません", 61, 1021502, 139002, 201, "2026/03/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 6, 1, 6.173, 0.0, "ルルィ", 10215, "ましゃか、グレイス姉しゃまたちが\nへんたいふしんしゃさんだなんて…\n騎士しゃん。あたちたちも協力ちて\n二人の破滅エンドを回避ちましょう", 61, 1021503, 136902, 301, "2026/03/31 12:00:00", -285.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 3.414, 0.0, "カリン", 2, "ミッションをクリアすると、\n報酬がもらえますよ！\n頑張ってください", 62, 2000001, 190801, 1, "2026/04/10 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 3.099, 0.0, "カリン", 2, "ミッションをクリアして、\n報酬をゲットしましょう！", 62, 2000002, 190801, 2, "2026/04/10 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 2.801, 0.0, "カリン", 2, "受け取ることができる\n報酬があるようです\n確認してみてください", 63, 2000003, 190801, 3, "2026/04/10 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 2, 0.0, 0.0, "カリン", 2, "報酬がもらえますよ！\nチェックしてみてください", 63, 2000004, 190801, 4, "2026/04/10 12:00:00", -416.5);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1, 2.12, 0.0, "カリン", 2, "ギルド管理協会です！\nイベント報酬券をお持ちでしたら、様々なアイテムと交換できますよ", 64, 2000005, 190801, 5, "2026/04/10 12:00:00", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 1, 2, 1.68, 0.0, "カリン", 2, "お疲れさまです！\nこちらでイベント報酬券とアイテムを交換することができますよ", 64, 2000006, 190801, 6, "2026/04/10 12:00:00", -363.0);
INSERT INTO `v1_ee40c0099888c2f48a09d48a47942ab1dbfd4f92b945836cfa1418d067d64ed7` VALUES ("2030/01/01 14:59:59", 2, 1, 2.33, 0.0, "カリン", 2, "いつもありがとうございます！\n報酬交換ですか？\nでは、イベント報酬券とお引き換えいたしますね", 64, 2000007, 190801, 7, "2026/04/10 12:00:00", -363.0);
